import type {
  AnalyticsQuery,
  DashboardData,
  MetricSummary,
  MetricType,
  TimeGranularity,
  TimeSeriesPoint,
  TopProductEntry,
  RecentOrderSummary,
} from '../models/analytics.js';
import type { Order } from '../models/order.js';
import type { User } from '../models/user.js';
import type { OrderRepository } from '../repositories/order.repository.js';
import type { UserRepository } from '../repositories/user.repository.js';
import { Logger } from '../utils/logger.js';

export class AnalyticsService {
  private logger = new Logger('AnalyticsService');

  constructor(
    private orderRepository: OrderRepository,
    private userRepository: UserRepository,
  ) {}

  /**
   * Get the full dashboard data combining all analytics.
   * Composes from the other methods via Promise.all.
   */
  async getDashboard(query: AnalyticsQuery): Promise<DashboardData> {
    this.logger.info('Generating dashboard data');

    const [orderMetric, revenueMetric, userMetric, aovMetric] =
      await Promise.all([
        this.getMetric('orders', query),
        this.getMetric('revenue', query),
        this.getMetric('users', query),
        this.getMetric('average-order-value', query),
      ]);

    const [timeSeries, topProducts, recentOrders] = await Promise.all([
      this.getTimeSeries(query),
      this.getTopProducts(query),
      this.getRecentOrders(query),
    ]);

    return {
      metrics: [orderMetric, revenueMetric, userMetric, aovMetric],
      timeSeries,
      topProducts,
      recentOrders,
      generatedAt: new Date().toISOString(),
    };
  }

  /**
   * Get a single metric summary with period-over-period comparison.
   */
  async getMetric(type: MetricType, query: AnalyticsQuery): Promise<MetricSummary> {
    this.logger.info(`Computing metric: ${type}`);

    const start = new Date(query.startDate);
    const end = new Date(query.endDate);
    const durationMs = end.getTime() - start.getTime();
    const prevStart = new Date(start.getTime() - durationMs);
    const prevEnd = start;

    const currentOrders = this.getOrdersInRange(start, end);
    const previousOrders = this.getOrdersInRange(prevStart, prevEnd);

    const labels: Record<MetricType, string> = {
      'orders': 'Total Orders',
      'revenue': 'Total Revenue',
      'users': 'New Users',
      'average-order-value': 'Avg Order Value',
    };

    let current: number;
    let previous: number;

    switch (type) {
      case 'orders': {
        current = currentOrders.length;
        previous = previousOrders.length;
        break;
      }
      case 'revenue': {
        current = this.sumRevenue(currentOrders);
        previous = this.sumRevenue(previousOrders);
        break;
      }
      case 'users': {
        current = this.getUsersInRange(start, end).length;
        previous = this.getUsersInRange(prevStart, prevEnd).length;
        break;
      }
      case 'average-order-value': {
        const currentRevenue = this.sumRevenue(currentOrders);
        const previousRevenue = this.sumRevenue(previousOrders);
        current = currentOrders.length > 0 ? currentRevenue / currentOrders.length : 0;
        previous = previousOrders.length > 0 ? previousRevenue / previousOrders.length : 0;
        break;
      }
    }

    const changePercent = previous !== 0
      ? ((current - previous) / previous) * 100
      : current > 0 ? 100 : 0;

    const trend: MetricSummary['trend'] =
      changePercent > 0 ? 'up' : changePercent < 0 ? 'down' : 'flat';

    return {
      type,
      label: labels[type],
      current: Math.round(current * 100) / 100,
      previous: Math.round(previous * 100) / 100,
      changePercent: Math.round(changePercent * 100) / 100,
      trend,
    };
  }

  /**
   * Get time series data for charting.
   * Groups orders by time bucket based on granularity, filling empty buckets with 0.
   */
  async getTimeSeries(query: AnalyticsQuery): Promise<TimeSeriesPoint[]> {
    this.logger.info(`Computing time series (${query.granularity})`);

    const start = new Date(query.startDate);
    const end = new Date(query.endDate);
    const orders = this.getOrdersInRange(start, end);

    const buckets = this.generateBuckets(start, end, query.granularity);
    const points: TimeSeriesPoint[] = buckets.map((bucketStart) => ({
      timestamp: bucketStart.toISOString(),
      value: 0,
    }));

    for (const order of orders) {
      const bucketIndex = this.findBucketIndex(order.createdAt, buckets);
      if (bucketIndex >= 0 && bucketIndex < points.length) {
        points[bucketIndex].value += 1;
      }
    }

    return points;
  }

  /**
   * Get top products ranked by revenue.
   */
  async getTopProducts(query: AnalyticsQuery, limit: number = 10): Promise<TopProductEntry[]> {
    this.logger.info(`Computing top ${limit} products`);

    const start = new Date(query.startDate);
    const end = new Date(query.endDate);
    const orders = this.getOrdersInRange(start, end);

    const productMap = new Map<string, { name: string; totalQuantity: number; totalRevenue: number }>();

    for (const order of orders) {
      for (const item of order.items) {
        const existing = productMap.get(item.productId);
        const itemRevenue = item.quantity * item.unitPrice;
        if (existing) {
          existing.totalQuantity += item.quantity;
          existing.totalRevenue += itemRevenue;
        } else {
          productMap.set(item.productId, {
            name: item.name,
            totalQuantity: item.quantity,
            totalRevenue: itemRevenue,
          });
        }
      }
    }

    return Array.from(productMap.entries())
      .map(([productId, data]) => ({
        productId,
        name: data.name,
        totalQuantity: data.totalQuantity,
        totalRevenue: Math.round(data.totalRevenue * 100) / 100,
      }))
      .sort((a, b) => b.totalRevenue - a.totalRevenue)
      .slice(0, limit);
  }

  /**
   * Get recent orders for the activity feed.
   */
  async getRecentOrders(query: AnalyticsQuery, limit: number = 10): Promise<RecentOrderSummary[]> {
    this.logger.info(`Fetching ${limit} recent orders`);

    const start = new Date(query.startDate);
    const end = new Date(query.endDate);
    const orders = this.getOrdersInRange(start, end);

    const userMap = new Map<string, User>();
    const users = this.userRepository.findAll();
    for (const user of users) {
      userMap.set(user.id, user);
    }

    return orders
      .sort((a, b) => b.createdAt.getTime() - a.createdAt.getTime())
      .slice(0, limit)
      .map((order) => {
        const user = userMap.get(order.userId);
        return {
          orderId: order.id,
          userName: user ? user.name : 'Unknown User',
          total: order.total,
          status: order.status,
          createdAt: order.createdAt.toISOString(),
        };
      });
  }

  private getOrdersInRange(start: Date, end: Date): Order[] {
    return this.orderRepository.findAll(
      (order) => order.createdAt >= start && order.createdAt < end,
    );
  }

  private getUsersInRange(start: Date, end: Date): User[] {
    return this.userRepository.findAll(
      (user) => user.createdAt >= start && user.createdAt < end,
    );
  }

  private sumRevenue(orders: Order[]): number {
    return orders.reduce((sum, order) => sum + order.total, 0);
  }

  private generateBuckets(start: Date, end: Date, granularity: TimeGranularity): Date[] {
    const buckets: Date[] = [];
    const current = new Date(start);

    while (current < end) {
      buckets.push(new Date(current));
      switch (granularity) {
        case 'hour':
          current.setUTCHours(current.getUTCHours() + 1);
          break;
        case 'day':
          current.setUTCDate(current.getUTCDate() + 1);
          break;
        case 'week':
          current.setUTCDate(current.getUTCDate() + 7);
          break;
        case 'month':
          current.setUTCMonth(current.getUTCMonth() + 1);
          break;
      }
    }

    return buckets;
  }

  private findBucketIndex(date: Date, buckets: Date[]): number {
    for (let i = buckets.length - 1; i >= 0; i--) {
      if (date >= buckets[i]) {
        return i;
      }
    }
    return -1;
  }
}

